CustomField.formula:
IF(
    ISPICKVAL(mfg_Schedule_Frequency__c, "") 
    || ISBLANK(mfg_Activation_Date__c) 
    || ISBLANK(mfg_Schedule_count__c),
    NULL,

    /* DAILY */
    IF(
        ISPICKVAL(mfg_Schedule_Frequency__c, "Daily"),
        mfg_Activation_Date__c + (mfg_Schedule_count__c - 1),

        /* WEEKLY */
        IF(
            ISPICKVAL(mfg_Schedule_Frequency__c, "Weekly"),
            mfg_Activation_Date__c + (mfg_Schedule_count__c * 7),

            /* MONTHLY */
            IF(
                ISPICKVAL(mfg_Schedule_Frequency__c, "Monthly"),
                ADDMONTHS(mfg_Activation_Date__c, mfg_Schedule_count__c) - 1,

                /* QUARTERLY */
                IF(
                    ISPICKVAL(mfg_Schedule_Frequency__c, "Quarterly"),
                    ADDMONTHS(mfg_Activation_Date__c, mfg_Schedule_count__c * 3) - 1,

                    /* YEARLY */
                    IF(
                        ISPICKVAL(mfg_Schedule_Frequency__c, "Yearly"),
                        ADDMONTHS(mfg_Activation_Date__c, mfg_Schedule_count__c * 12) - 1,

                        /* ONE-TIME */
                        IF(
                            ISPICKVAL(mfg_Schedule_Frequency__c, "One-Time"),
                            mfg_Activation_Date__c,

                            /* DEFAULT */
                            NULL
                        )
                    )
                )
            )
        )
    )
)
